<script>
let value=$state(""),query=$state(''),open=$state(false),message=$state('Ready'),page=$state(1);let range=['',''],start=$state(range[0]),end=$state(range[1]);const matches=x=>x.toLowerCase().includes(query.toLowerCase());function choose(x){value=x;query=x;open=false}function chooseKey(e,x){if(e.key==='Enter'||e.key===' '){e.preventDefault();choose(x)}}function key(e){if(e.key==='Escape')open=false;else if(e.key==='ArrowDown'||e.key==='ArrowUp'){e.preventDefault();open=true}}
</script>
<main class="family"><h1>CommandPalette</h1><section><button class="command" aria-haspopup="dialog" onclick={()=>open=true}>Open commands ⌘K</button>{#if open}<div class="palette" role="dialog" aria-label="Command palette" aria-modal="true" tabindex="-1" onkeydown={key}><input aria-label="Filter commands" bind:value={query}><ul role="listbox">{#if matches("Create project")}<li role="option" tabindex="-1" aria-selected={false}>Create project</li>{/if}{#if matches("Open settings")}<li role="option" tabindex="-1" aria-selected={false}>Open settings</li>{/if}</ul></div>{/if}</section></main>
